#include<bits/stdc++.h>
int n,k,a[100010],b[100010],ans;
int check(int x){
	int ans=0;
	for(int i=0;i<n;i++)ans+=(a[i]/x)*(b[i]/x);
	return ans>=k;
}
int main(void){
	scanf("%d%d",&n,&k);
	for(int i=0;i<n;i++)scanf("%d%d",a+i,b+i);
	int l=1,r=100000;
	while(l<r){
		int mid=(l+r+1)>>1;
		if(check(mid))ans=mid,l=mid;
		else r=mid-1;
	}
	printf("%d\n",ans);return false;
}
